// ─── types ───────────────────────────────────────────────────────────────────

/// A single OHLCV bar.
#[derive(Clone, Debug)]
struct Bar {
    ts_ms: i64,
    open: f64,
    high: f64,
    low: f64,
    close: f64,
    volume: f64,
}

/// Chart rendering style.
#[derive(Clone, Copy, PartialEq, Eq, Debug)]
enum ChartType {
    Candle,
    HeikinAshi,
    Line,
    OhlcBars,
    Renko,
}

impl ChartType {
    fn label(self) -> &'static str {
        match self {
            ChartType::Candle     => "Candle",
            ChartType::HeikinAshi => "Heikin-Ashi",
            ChartType::Line       => "Line",
            ChartType::OhlcBars   => "OHLC Bars",
            ChartType::Renko      => "Renko",
        }
    }
}

/// Available timeframes for the selector toolbar.
#[derive(Clone, Copy, PartialEq, Eq, Debug)]
enum Timeframe {
    M1, M5, M15, M30, H1, H4, D1, W1, MN1,
}

impl Timeframe {
    fn label(self) -> &'static str {
        match self {
            Timeframe::M1  => "M1",
            Timeframe::M5  => "M5",
            Timeframe::M15 => "M15",
            Timeframe::M30 => "M30",
            Timeframe::H1  => "H1",
            Timeframe::H4  => "H4",
            Timeframe::D1  => "D1",
            Timeframe::W1  => "W1",
            Timeframe::MN1 => "MN1",
        }
    }

    /// Timeframe in minutes (used by ATR projection MTF).
    fn minutes(self) -> u32 {
        match self {
            Timeframe::M1  => 1,
            Timeframe::M5  => 5,
            Timeframe::M15 => 15,
            Timeframe::M30 => 30,
            Timeframe::H1  => 60,
            Timeframe::H4  => 240,
            Timeframe::D1  => 1440,
            Timeframe::W1  => 10080,
            Timeframe::MN1 => 43200,
        }
    }

    /// Build the cache key suffix used by the MT5 XML import pipeline.
    fn cache_suffix(self) -> &'static str {
        match self {
            Timeframe::M1  => "1Min",
            Timeframe::M5  => "5Min",
            Timeframe::M15 => "15Min",
            Timeframe::M30 => "30Min",
            Timeframe::H1  => "1Hour",
            Timeframe::H4  => "4Hour",
            Timeframe::D1  => "1Day",
            Timeframe::W1  => "1Week",
            Timeframe::MN1 => "1Month",
        }
    }
}

/// Log severity level.
#[derive(Clone, Debug)]
enum LogLevel {
    Info,
    Warn,
    Error,
}

/// A single log entry displayed in the bottom panel.
#[derive(Clone, Debug)]
struct LogEntry {
    level: LogLevel,
    msg: String,
}

/// Indicator-based alert condition.
#[derive(Clone)]
struct IndicatorAlert {
    symbol: String,
    timeframe: String,
    indicator: String,     // "RSI", "MACD", "Price", "Fisher", etc.
    condition: String,     // "crosses_above", "crosses_below", "greater_than", "less_than"
    threshold: f64,
    active: bool,
    triggered: bool,
    last_value: Option<f64>,
    #[allow(dead_code)]
    created_at: String,
}

const ALERT_INDICATORS: &[&str] = &["Price", "RSI", "Fisher", "MACD", "ATR", "ADX", "Stochastic %K", "CCI", "Volume"];
const ALERT_CONDITIONS: &[&str] = &["crosses above", "crosses below", "greater than", "less than"];

/// Trade Journal entry for tracking live/paper trades with notes.
#[derive(Clone)]
struct JournalEntry {
    timestamp: String,
    symbol: String,
    side: String,      // "BUY" or "SELL"
    qty: f64,
    entry_price: f64,
    exit_price: Option<f64>,
    pnl: Option<f64>,
    strategy: String,
    notes: String,
    #[allow(dead_code)]
    screenshot_path: Option<String>,
}

impl LogEntry {
    fn info(msg: impl Into<String>) -> Self { Self { level: LogLevel::Info,  msg: msg.into() } }
    fn warn(msg: impl Into<String>) -> Self { Self { level: LogLevel::Warn,  msg: msg.into() } }
    fn err (msg: impl Into<String>) -> Self { Self { level: LogLevel::Error, msg: msg.into() } }

    fn color(&self) -> egui::Color32 {
        match self.level {
            LogLevel::Info  => egui::Color32::from_rgb(160, 200, 160),
            LogLevel::Warn  => egui::Color32::from_rgb(255, 200, 50),
            LogLevel::Error => egui::Color32::from_rgb(255, 80, 80),
        }
    }

    fn prefix(&self) -> &'static str {
        match self.level {
            LogLevel::Info  => "[INFO] ",
            LogLevel::Warn  => "[WARN] ",
            LogLevel::Error => "[ERR]  ",
        }
    }
}

// ─── drawing tools ───────────────────────────────────────────────────────────

const HLINE_COL: egui::Color32 = egui::Color32::from_rgb(255, 200, 80);
const TRENDLINE_COL: egui::Color32 = egui::Color32::from_rgb(100, 200, 255);
const FIBO_COL: egui::Color32 = egui::Color32::from_rgb(200, 160, 100);

#[derive(Clone, Debug)]
enum Drawing {
    /// Horizontal price line.
    HLine { price: f64, color: egui::Color32 },
    /// Trendline between two (bar_index, price) points.
    TrendLine {
        p1: (usize, f64), // (absolute bar index, price)
        p2: (usize, f64),
        color: egui::Color32,
    },
    /// Fibonacci retracement between two price levels.
    FiboRetrace {
        high: f64,
        low: f64,
        bar_start: usize,
        bar_end: usize,
    },
    /// Vertical line at a bar index.
    #[allow(dead_code)]
    VLine { bar_idx: usize, color: egui::Color32 },
    /// Rectangle between two (bar, price) corners.
    #[allow(dead_code)]
    Rectangle {
        p1: (usize, f64),
        p2: (usize, f64),
        color: egui::Color32,
    },
    /// Ray from one point extending infinitely to the right.
    #[allow(dead_code)]
    Ray {
        origin: (usize, f64),
        slope: f64, // price per bar
        color: egui::Color32,
    },
    /// Parallel channel (trendline + offset).
    #[allow(dead_code)]
    Channel {
        p1: (usize, f64),
        p2: (usize, f64),
        width: f64, // price offset for parallel line
        color: egui::Color32,
    },
}

/// Trade marker for chart overlay (DARWIN deals, broker fills).
/// Aggregated: multiple deals at the same bar+price become one marker with combined volume.
#[derive(Clone, Debug)]
struct TradeMarker {
    bar_idx: usize,     // index into bars array
    price: f64,
    volume: f64,        // aggregated total lots
    is_buy: bool,       // true=buy, false=sell
    count: u32,         // number of individual deals aggregated
}

/// Open position line for chart overlay (entry, SL, TP).
#[derive(Clone, Debug)]
struct PositionLine {
    price: f64,
    volume: f64,       // aggregated lots at this price
    is_buy: bool,
    line_type: u8,     // 0=entry, 1=SL, 2=TP
}

/// Trade overlay data passed to draw_chart for DARWIN/broker position rendering.
#[derive(Clone, Debug, Default)]
struct TradeOverlay {
    markers: Vec<TradeMarker>,
    position_lines: Vec<PositionLine>,
}

/// Drawing interaction mode.
#[derive(Clone, Copy, PartialEq, Debug)]
enum DrawMode {
    None,
    PlacingHLine,
    PlacingTrendP1,
    PlacingTrendP2 { bar1: usize, price1: f64 },
    PlacingFiboP1,
    PlacingFiboP2 { bar1: usize, price1: f64 },
    PlacingVLine,
    PlacingRectP1,
    PlacingRectP2 { bar1: usize, price1: f64 },
    PlacingRayP1,
    PlacingRayP2 { bar1: usize, price1: f64 },
    PlacingChannelP1,
    PlacingChannelP2 { bar1: usize, price1: f64 },
    PlacingChannelP3 { bar1: usize, price1: f64, bar2: usize, price2: f64 },
}

