    fn dark_visuals() -> egui::Visuals {
        let mut v = egui::Visuals::dark();
        // ── TOTAL AESTHETIC OVERHAUL: square, compact, dark like Godel Terminal ──
        v.panel_fill                        = egui::Color32::from_rgb(0, 0, 0);
        v.window_fill                       = egui::Color32::from_rgb(10, 10, 18);      // very dark blue-black
        v.extreme_bg_color                  = egui::Color32::from_rgb(0, 0, 0);
        v.faint_bg_color                    = egui::Color32::from_rgb(8, 8, 14);
        // Widget colors — dark blue inputs, minimal contrast
        v.widgets.noninteractive.bg_fill    = egui::Color32::from_rgb(8, 8, 14);
        v.widgets.noninteractive.fg_stroke  = egui::Stroke::new(1.0, egui::Color32::from_rgb(180, 180, 190));
        v.widgets.noninteractive.bg_stroke  = egui::Stroke::new(0.5, egui::Color32::from_rgb(30, 30, 40));
        v.widgets.inactive.bg_fill          = egui::Color32::from_rgb(15, 20, 35);      // dark blue input bg
        v.widgets.inactive.bg_stroke        = egui::Stroke::new(0.5, egui::Color32::from_rgb(40, 45, 60));
        v.widgets.hovered.bg_fill           = egui::Color32::from_rgb(20, 30, 55);
        v.widgets.hovered.bg_stroke         = egui::Stroke::new(1.0, egui::Color32::from_rgb(60, 70, 100));
        v.widgets.active.bg_fill            = egui::Color32::from_rgb(15, 40, 80);
        v.selection.bg_fill                 = egui::Color32::from_rgb(15, 40, 80);
        v.selection.stroke                  = egui::Stroke::new(1.0, egui::Color32::from_rgb(100, 140, 255));
        // Windows — SQUARE corners, thin border, minimal shadow
        v.window_stroke                     = egui::Stroke::new(1.0, egui::Color32::from_rgb(40, 42, 54));
        v.window_shadow                     = egui::Shadow { offset: [1, 2], blur: 4, spread: 0, color: egui::Color32::from_rgba_premultiplied(0, 0, 0, 120) };
        v.window_corner_radius              = egui::CornerRadius::same(0);  // SQUARE
        v.menu_corner_radius                = egui::CornerRadius::same(0);  // SQUARE
        // Separator
        v.widgets.noninteractive.corner_radius = egui::CornerRadius::same(0);
        v
    }

    fn reload_symbol(&mut self, symbol: &str, tf: Timeframe) {
        if let Some(ref cache) = self.cache {
            let chart_type = self.charts.get(self.active_tab).map(|c| c.chart_type).unwrap_or(ChartType::Candle);
            let mut chart = ChartState::new(symbol, tf);
            chart.chart_type = chart_type;
            let cache_ref = Arc::as_ref(cache);
            { let mut gpu = self.gpu_indicators.take(); chart.load(cache_ref, &mut self.log, gpu.as_mut()); self.gpu_indicators = gpu; }
            // If chart loaded 0 bars, trigger live fetch from Alpaca
            if chart.bars.is_empty() {
                let mut db_path = dirs_home(); db_path.push("cache"); db_path.push("typhoon_cache.db");
                let _ = self.broker_tx.send(BrokerCmd::FetchBars {
                    symbol: symbol.to_string(),
                    timeframe: tf.cache_suffix().to_string(),
                    db_path,
                });
                self.log.push_back(LogEntry::info(format!("No cached data for {} {} — fetching from Alpaca...", symbol, tf.label())));
            }
            if let Some(target) = self.charts.get_mut(self.active_tab) {
                *target = chart;
            }
        } else {
            self.log.push_back(LogEntry::warn("Cache not available"));
        }
    }

    /// Set up MTF grid with N columns and target chart count.
    /// Creates charts for all 9 timeframes, filling up to `target` charts.
    fn setup_mtf_grid(&mut self, cols: usize, target: usize) {
        let all_tfs = [
            Timeframe::M1, Timeframe::M5, Timeframe::M15, Timeframe::M30,
            Timeframe::H1, Timeframe::H4, Timeframe::D1, Timeframe::W1, Timeframe::MN1,
        ];
        let sym = self.symbol_input.trim().to_string();
        // Grow charts to target count
        while self.charts.len() < target {
            let tf_idx = self.charts.len() % all_tfs.len();
            let mut chart = ChartState::new(&sym, all_tfs[tf_idx]);
            if let Some(ref cache) = self.cache {
                { let mut gpu = self.gpu_indicators.take(); chart.load(cache, &mut self.log, gpu.as_mut()); self.gpu_indicators = gpu; }
            }
            self.charts.push(chart);
        }
        // Load any existing charts that have empty bars (e.g. from session restore)
        if let Some(ref cache) = self.cache {
            for chart in &mut self.charts {
                if chart.bars.is_empty() {
                    { let mut gpu = self.gpu_indicators.take(); chart.load(cache, &mut self.log, gpu.as_mut()); self.gpu_indicators = gpu; }
                }
            }
        }
        self.mtf_cols = cols;
        self.mtf_enabled = true;
        self.log.push_back(LogEntry::info(format!("MTF grid: {}×{} ({} charts)", cols, (target + cols - 1) / cols, self.charts.len())));
    }

    /// Build trade overlay for a chart: DARWIN deals as arrows + open position lines.
    /// Aggregates same-price entries at same bar into single markers.
    fn build_trade_overlay(&self, chart: &ChartState) -> TradeOverlay {
        let mut overlay = TradeOverlay::default();
        if chart.bars.is_empty() { return overlay; }

        // Extract bare symbol from chart symbol for matching
        let bare_sym = {
            let s = &chart.symbol;
            let parts: Vec<&str> = s.split(':').collect();
            let is_tf = matches!(parts.last().copied(), Some("1Min"|"5Min"|"15Min"|"30Min"|"1Hour"|"4Hour"|"1Day"|"1Week"|"1Month"));
            let sym_parts = if is_tf && parts.len() > 1 { &parts[..parts.len()-1] } else { &parts[..] };
            sym_parts.last().copied().unwrap_or(s.as_str()).to_string()
        };
        if bare_sym.is_empty() { return overlay; }

        let first_ts = chart.bars.first().map(|b| b.ts_ms).unwrap_or(0);
        let last_ts = chart.bars.last().map(|b| b.ts_ms).unwrap_or(0);

        // Parse MQL5 time string "YYYY.MM.DD HH:MM:SS" to epoch ms
        let parse_time = |s: &str| -> i64 {
            // "2024.10.08 16:47:19" → chrono parse
            let s = s.replace('.', "-");
            chrono::NaiveDateTime::parse_from_str(&s, "%Y-%m-%d %H:%M:%S")
                .map(|dt| dt.and_utc().timestamp_millis())
                .unwrap_or(0)
        };

        // Find bar index for a timestamp (binary search on sorted bars)
        let find_bar = |ts_ms: i64| -> Option<usize> {
            if ts_ms < first_ts || ts_ms > last_ts + 86_400_000 { return None; }
            match chart.bars.binary_search_by_key(&ts_ms, |b| b.ts_ms) {
                Ok(idx) => Some(idx),
                Err(idx) => if idx > 0 { Some(idx - 1) } else { Some(0) },
            }
        };

        // Collect deals from all DARWIN accounts matching this symbol
        use std::collections::HashMap;
        let mut marker_map: HashMap<(usize, bool, i64), (f64, u32)> = HashMap::new(); // (bar_idx, is_buy, price_cents) → (total_vol, count)

        for det in &self.bg.account_details {
            // Check closed positions (have SL/TP)
            for pos in &det.closed_positions {
                if pos.symbol != bare_sym { continue; }
                // Entry arrow
                let ts = parse_time(&pos.open_time);
                if let Some(bar_idx) = find_bar(ts) {
                    let is_buy = pos.pos_type == "buy";
                    let price_key = (pos.open_price * 100000.0) as i64;
                    let entry = marker_map.entry((bar_idx, is_buy, price_key)).or_insert((0.0, 0));
                    entry.0 += pos.volume;
                    entry.1 += 1;
                }
                // Exit arrow (opposite direction)
                if !pos.close_time.is_empty() {
                    let ts = parse_time(&pos.close_time);
                    if let Some(bar_idx) = find_bar(ts) {
                        let is_buy = pos.pos_type != "buy"; // exit is opposite
                        let price_key = (pos.close_price * 100000.0) as i64;
                        let entry = marker_map.entry((bar_idx, is_buy, price_key)).or_insert((0.0, 0));
                        entry.0 += pos.volume;
                        entry.1 += 1;
                    }
                }
            }
            // Check recent deals
            for deal in &det.recent_deals {
                if deal.symbol != bare_sym { continue; }
                if deal.direction.is_empty() { continue; } // skip balance entries
                let ts = parse_time(&deal.time);
                if let Some(bar_idx) = find_bar(ts) {
                    let is_buy = deal.deal_type == "buy";
                    let price_key = (deal.price * 100000.0) as i64;
                    let entry = marker_map.entry((bar_idx, is_buy, price_key)).or_insert((0.0, 0));
                    entry.0 += deal.volume;
                    entry.1 += 1;
                }
            }

            // Open position lines (entry, SL, TP)
            for pos in &det.open_positions {
                if pos.symbol != bare_sym { continue; }
                let is_buy = pos.side == "buy";
                overlay.position_lines.push(PositionLine {
                    price: pos.avg_price,
                    volume: pos.total_volume,
                    is_buy,
                    line_type: 0, // entry
                });
            }
        }

        // Also check portfolio-level positions for SL/TP from closed_positions
        // (Open positions from DarwinOpenPosition don't have SL/TP; closed ones do)

        // Broker fills (Alpaca/tastytrade) — add to marker map before conversion
        for (sym, side, qty, price, time) in &self.recent_fills {
            let fill_sym = sym.replace('/', "");
            if !fill_sym.contains(&bare_sym) && !bare_sym.contains(&fill_sym) { continue; }
            let ts = chrono::NaiveDateTime::parse_from_str(time, "%Y-%m-%dT%H:%M:%S%.fZ")
                .or_else(|_| chrono::NaiveDateTime::parse_from_str(time, "%Y-%m-%d %H:%M:%S"))
                .or_else(|_| chrono::NaiveDate::parse_from_str(time, "%Y-%m-%d").map(|d| d.and_hms_opt(0, 0, 0).unwrap()))
                .map(|dt| dt.and_utc().timestamp_millis())
                .unwrap_or(0);
            if let Some(bar_idx) = find_bar(ts) {
                let is_buy = side == "buy";
                let price_key = (*price * 100000.0) as i64;
                let entry = marker_map.entry((bar_idx, is_buy, price_key)).or_insert((0.0, 0));
                entry.0 += qty;
                entry.1 += 1;
            }
        }

        // Convert marker map to sorted markers
        for ((bar_idx, is_buy, price_key), (volume, count)) in marker_map {
            overlay.markers.push(TradeMarker {
                bar_idx,
                price: price_key as f64 / 100000.0,
                volume,
                is_buy,
                count,
            });
        }
        overlay.markers.sort_by_key(|m| m.bar_idx);

        // Live broker position lines
        for pos in &self.live_positions {
            let pos_sym = pos.symbol.replace('/', "");
            if !pos_sym.contains(&bare_sym) && !bare_sym.contains(&pos_sym) { continue; }
            let is_buy = pos.side == "long";
            overlay.position_lines.push(PositionLine {
                price: pos.avg_entry_price,
                volume: pos.qty,
                is_buy,
                line_type: 0, // entry
            });
        }

        // Deduplicate position lines (aggregate same price+type)
        {
            let mut agg: HashMap<(i64, u8), (f64, bool)> = HashMap::new();
            for pl in &overlay.position_lines {
                let key = ((pl.price * 100000.0) as i64, pl.line_type);
                let entry = agg.entry(key).or_insert((0.0, pl.is_buy));
                entry.0 += pl.volume;
            }
            overlay.position_lines = agg.into_iter().map(|((pk, lt), (vol, is_buy))| {
                PositionLine { price: pk as f64 / 100000.0, volume: vol, is_buy, line_type: lt }
            }).collect();
        }

        overlay
    }

    fn indicator_flags(&self) -> IndicatorFlags {
        IndicatorFlags {
            sma200: self.show_sma200,
            sma100: self.show_sma100,
            kama: self.show_kama,
            ema21: self.show_ema21,
            bollinger: self.show_bollinger,
            ichimoku: self.show_ichimoku,
            wma: self.show_wma,
            hma: self.show_hma,
            psar: self.show_psar,
            atr_proj: self.show_atr_proj,
            prev_levels: self.show_prev_levels,
            pivots: self.show_pivots,
            fractals: self.show_fractals,
            harmonics: self.show_harmonics,
            auto_fib: self.show_auto_fib,
            supply_demand: self.show_supply_demand,
            ehlers_ss: self.show_ehlers_ss,
            ehlers_decycler: self.show_ehlers_decycler,
            ehlers_itl: self.show_ehlers_itl,
            ehlers_mama: self.show_ehlers_mama,
        }
    }

    fn handle_command(&mut self, cmd: &str, ctx: &egui::Context) {
        let cmd_upper = cmd.trim().to_uppercase();
        self.log.push_back(LogEntry::info(format!("CMD: {}", cmd_upper)));
        match cmd_upper.as_str() {
            "QUIT" => {
                self.save_session();
                ctx.send_viewport_cmd(egui::ViewportCommand::Close);
            }
            "MTF" | "MTF_GRID" => {
                self.mtf_enabled = !self.mtf_enabled;
                // When enabling MTF grid, load any charts with empty bars
                if self.mtf_enabled {
                    if let Some(ref cache) = self.cache.clone() {
                        for chart in &mut self.charts {
                            if chart.bars.is_empty() {
                                { let mut gpu = self.gpu_indicators.take(); chart.load(Arc::as_ref(cache), &mut self.log, gpu.as_mut()); self.gpu_indicators = gpu; }
                            }
                        }
                    }
                }
                self.log.push_back(LogEntry::info(format!("MTF grid: {}", self.mtf_enabled)));
            }
            "MTF_2X2" => { self.setup_mtf_grid(2, 4); }
            "MTF_3X3" => { self.setup_mtf_grid(3, 9); }
            "MTF_4X4" => { self.setup_mtf_grid(4, 16); }
            "MTF_4X3" => { self.setup_mtf_grid(4, 12); }
            "RELOAD" => {
                if let Some(ref cache) = self.cache.clone() {
                    for chart in &mut self.charts {
                        { let mut gpu = self.gpu_indicators.take(); chart.load(Arc::as_ref(cache), &mut self.log, gpu.as_mut()); self.gpu_indicators = gpu; }
                    }
                }
            }
            "CONNECT"       => self.show_connect = true,
            "SETTINGS"      => self.show_settings = true,
            "INDICATORS"    => self.show_indicators_panel = !self.show_indicators_panel,
            "DARWIN"        => self.show_darwin_accounts = true,
            "PORTFOLIO"     => self.show_darwin_portfolio = true,
            "OVERLAP"       => self.show_symbol_overlap = true,
            "BACKTEST"      => self.show_backtest = true,
            "SCREENER"      => self.show_screener = true,
            "OPTIMIZER"     => self.show_optimizer = true,
            "RISK_CALC"     => self.show_risk_calc = true,
            "VAR"           => self.show_var_mult = true,
            "MARGIN"        => self.show_margin_monitor = true,
            "FRED" => {
                if self.fred_key.is_empty() {
                    self.log.push_back(LogEntry::warn("Set FRED API Key in Settings first"));
                } else {
                    self.show_fred = true;
                    let key = self.fred_key.clone();
                    let _ = self.broker_tx.send(BrokerCmd::FredFetch { api_key: key });
                }
            }
            "NEWS"          => self.show_news = true,
            "CALENDAR"      => self.show_calendar = true,
            "SEC"           => self.show_sec = true,
            "INSIDER"       => self.show_insider = true,
            "FUNDAMENTALS"  => self.show_fundamentals = true,
            "EV"            => self.show_ev_scanner = true,
            "EARNINGS"      => self.show_earnings_calendar = true,
            "DIVIDENDS"     => self.show_dividend_calendar = true,
            "EVSCRAPE"      => {
                let mut db_path = dirs_home();
                db_path.push("cache");
                db_path.push("typhoon_cache.db");
                let _ = self.broker_tx.send(BrokerCmd::FundamentalsScrape { db_path });
                self.log.push_back(LogEntry::info("Fundamentals scrape started for all MT5 symbols..."));
            }
            "MT5SYNC"       => {
                let paths: Vec<String> = self.mt5_db_paths.iter()
                    .filter(|p| !p.is_empty() && std::path::Path::new(p.as_str()).exists())
                    .cloned().collect();
                if paths.is_empty() {
                    self.log.push_back(LogEntry::warn("No valid MT5 database paths configured — set them in Settings"));
                } else {
                    let mut db_path = dirs_home();
                    db_path.push("cache");
                    db_path.push("typhoon_cache.db");
                    let _ = self.broker_tx.send(BrokerCmd::Mt5Sync { sources: paths.clone(), target: db_path });
                    self.log.push_back(LogEntry::info(format!("MT5 sync started ({} sources)...", paths.len())));
                }
            }
            "ANALYST"       => self.show_analyst = true,
            "HOLDERS"       => self.show_holders = true,
            "CORRELATION"   => self.show_correlation = true,
            "SEASONALS"     => self.show_seasonals = true,
            "MONTECARLO"    => self.show_montecarlo = true,
            "STRESS_TEST"   => self.show_stress_test = true,
            "VOLUME_PROFILE"=> self.show_volume_profile = true,
            "ORDER_FLOW"    => self.show_order_flow = true,
            "BOOKMAP"       => self.show_bookmap = true,
            "JOURNAL"       => self.show_journal = true,
            "CACHE_STATS"   => self.show_cache_stats = true,
            "STORAGE"       => self.show_storage = true,
            "LAN_SYNC"      => self.show_lan_sync = true,
            "UNUSUAL_VOLUME" => {
                self.show_unusual_volume = true;
                // Scan from cache
                if let Some(ref cache) = self.cache {
                    let mut results: Vec<(String, f64, f64, f64)> = Vec::new();
                    for (key, count, _) in &self.bg.detailed_stats {
                        if *count < 30 { continue; }
                        if !key.contains(":1Day") { continue; }
                        if let Ok(Some(raw)) = cache.get_bars_raw(key) {
                            let n = raw.len();
                            if n < 21 { continue; }
                            let today_vol = raw[n-1].5;
                            let avg_vol: f64 = raw[n-21..n-1].iter().map(|r| r.5).sum::<f64>() / 20.0;
                            if avg_vol > 0.0 {
                                let ratio = today_vol / avg_vol;
                                if ratio > 1.5 {
                                    let parts: Vec<&str> = key.split(':').collect();
                                    let sym = if parts.len() >= 3 { parts[parts.len()-2] } else { key };
                                    results.push((sym.to_string(), today_vol, avg_vol, ratio));
                                }
                            }
                        }
                    }
                    results.sort_by(|a, b| b.3.partial_cmp(&a.3).unwrap_or(std::cmp::Ordering::Equal));
                    self.unusual_volume_results = results;
                    self.log.push_back(LogEntry::info(format!("Unusual volume: {} symbols flagged", self.unusual_volume_results.len())));
                }
            }
            "SECTOR_ROTATION" => self.show_sector_rotation = true,
            "ECON_CALENDAR" => {
                self.show_econ_calendar = true;
                if self.econ_events.is_empty() {
                    let _ = self.broker_tx.send(BrokerCmd::FetchEconCalendar { finnhub_key: self.finnhub_key.clone() });
                }
            }
            "CONGRESS" => {
                self.show_congress = true;
                if self.congress_trades.is_empty() {
                    let _ = self.broker_tx.send(BrokerCmd::FetchCongressTrades);
                }
            }
            "HELP"          => self.show_help = true,
            "FULLSCREEN"    => ctx.send_viewport_cmd(egui::ViewportCommand::Fullscreen(true)),
            "CLOSE_WINDOWS" => self.close_all_windows(),
            "NEW_WINDOW" | "POPOUT" => {
                let exe = std::env::current_exe().unwrap_or_default();
                match std::process::Command::new(&exe).spawn() {
                    Ok(_) => self.log.push_back(LogEntry::info("New window launched (separate process)")),
                    Err(e) => self.log.push_back(LogEntry::err(format!("Failed to launch new window: {}", e))),
                }
            }
            // Chart types
            "CANDLE"     => { if let Some(c) = self.charts.get_mut(self.active_tab) { c.chart_type = ChartType::Candle; } }
            "HEIKINASHI" => { if let Some(c) = self.charts.get_mut(self.active_tab) { c.chart_type = ChartType::HeikinAshi; } }
            "LINE"       => { if let Some(c) = self.charts.get_mut(self.active_tab) { c.chart_type = ChartType::Line; } }
            "OHLC"       => { if let Some(c) = self.charts.get_mut(self.active_tab) { c.chart_type = ChartType::OhlcBars; } }
            "RENKO"      => { if let Some(c) = self.charts.get_mut(self.active_tab) { c.chart_type = ChartType::Renko; } }
            "EXPORT_CSV" => { self.export_csv(); }
            // Tabs
            "NEW_TAB" => {
                let tf = self.charts.get(self.active_tab).map(|c| c.timeframe).unwrap_or(Timeframe::H4);
                let mut new_chart = ChartState::new(&self.symbol_input, tf);
                if let Some(ref cache) = self.cache.clone() {
                    { let mut gpu = self.gpu_indicators.take(); new_chart.load(Arc::as_ref(cache), &mut self.log, gpu.as_mut()); self.gpu_indicators = gpu; }
                }
                self.charts.push(new_chart);
                self.active_tab = self.charts.len() - 1;
            }
            "CLOSE_TAB" => {
                if self.charts.len() > 1 {
                    self.charts.remove(self.active_tab);
                    if self.active_tab >= self.charts.len() {
                        self.active_tab = self.charts.len() - 1;
                    }
                }
            }
            // DARWIN-specific
            "DARWINS"       => self.show_darwin_portfolio = true,
            "DRAWDOWN"      => { self.darwin_view = 0; self.show_darwin_portfolio = true; } // Portfolio Summary with per-DARWIN DD%
            "REBALANCE"     => { self.darwin_view = 18; self.show_darwin_portfolio = true; } // Optimal Allocation view
            "DARWIN_TRADES" => { self.log.push_back(LogEntry::info("DARWIN trade markers: open DARWIN Accounts for deal history")); self.show_darwin_accounts = true; }
            "DSCORE"        => { self.show_var_mult = true; }
            "DARWIN_BROWSER" => { self.show_darwin_browser = true; }
            "RISKRUIN" => self.show_risk_ruin = true,
            "REPLAY" => {
                self.replay_active = !self.replay_active;
                if self.replay_active {
                    if let Some(chart) = self.charts.get(self.active_tab) {
                        self.replay_bar_idx = chart.bars.len().saturating_sub(100); // start 100 bars from end
                    }
                    self.log.push_back(LogEntry::info("Replay mode ON — use arrow keys to step"));
                } else {
                    self.log.push_back(LogEntry::info("Replay mode OFF"));
                }
            }
            "ALERTS" => {
                self.show_alert_builder = true;
                self.alert_symbol = self.charts.get(self.active_tab).map(|c| c.symbol.clone()).unwrap_or_default();
            }
            "DARWINEXOUTLIERS" => {
                // Multi-dimensional outlier detection: VaR + EV + ATR + SEC + Volume
                if let Some(ref cache) = self.cache {
                    if let Some(_conn) = cache.try_connection() {
                        use typhoon_engine::core::var;
                        let fund = &self.bg.all_fundamentals;
                        if fund.len() < 10 {
                            self.log.push_back(LogEntry::warn("Need 10+ symbols with fundamentals data. Run EVSCRAPE first."));
                        } else {
                            // Build per-symbol data maps from all available sources
                            let mut symbols: Vec<(String, String)> = Vec::new();
                            let mut ev_map = std::collections::HashMap::new();
                            let mut var_map = std::collections::HashMap::new();
                            let mut atr_map = std::collections::HashMap::new();
                            let mut sec_map = std::collections::HashMap::new();

                            for f in fund {
                                let sector = if f.sector.is_empty() { "Unknown".to_string() } else { f.sector.clone() };
                                symbols.push((f.symbol.clone(), sector));
                                // EV: MCap/EV ratio (valuation anomaly)
                                if let (Some(mc), Some(ev)) = (f.market_cap, f.enterprise_value) {
                                    if ev > 0.0 { ev_map.insert(f.symbol.clone(), mc / ev * 100.0); }
                                }
                                // P/E as proxy for VaR (extreme P/E = risk)
                                if let Some(pe) = f.pe_ratio {
                                    if pe.abs() > 0.0 { var_map.insert(f.symbol.clone(), pe.abs()); }
                                }
                                // Short ratio as ATR proxy (high short = volatility risk)
                                if let Some(sr) = f.short_ratio {
                                    if sr > 0.0 { atr_map.insert(f.symbol.clone(), sr); }
                                }
                            }
                            // SEC filings per symbol — initialize ALL symbols to 0 first
                            // so z-score sees full distribution (not just non-zero entries)
                            for (sym, _) in &symbols {
                                sec_map.entry(sym.clone()).or_insert(0);
                            }
                            for filing in &self.bg.sec_filings {
                                *sec_map.entry(filing.ticker.clone()).or_insert(0) += 1;
                            }
                            // Also count insider trades
                            for (ticker, trades) in &self.bg.insider_trades {
                                *sec_map.entry(ticker.clone()).or_insert(0) += trades.len() as i32;
                            }

                            // Run multi-dimensional outlier detection
                            let multi = var::detect_multi_outliers(&symbols, &var_map, &ev_map, &atr_map, &sec_map, 1.5);
                            // Also run single-dimension (legacy) for sector stats
                            let data: Vec<(String, String, f64)> = fund.iter()
                                .filter_map(|f| f.market_cap.map(|mc| (f.symbol.clone(), if f.sector.is_empty() { "Unknown".to_string() } else { f.sector.clone() }, mc)))
                                .filter(|(_, _, mc)| *mc > 0.0)
                                .collect();
                            let (outliers, stats) = var::detect_outliers(&data, 1.5);

                            let extreme = multi.iter().filter(|o| o.dimensions_flagged >= 3).count();
                            let high = multi.iter().filter(|o| o.dimensions_flagged == 2).count();
                            self.log.push_back(LogEntry::info(format!(
                                "Multi-outlier scan: {} total ({} EXTREME, {} HIGH) from {} symbols | VaR:{} EV:{} ATR:{} SEC:{}",
                                multi.len(), extreme, high, symbols.len(),
                                var_map.len(), ev_map.len(), atr_map.len(), sec_map.len()
                            )));
                            self.darwinex_outliers = outliers;
                            self.darwinex_sector_stats = stats;
                            self.darwinex_multi_outliers = multi;
                            self.show_darwinex_outliers = true;
                        }
                    }
                }
            }
            "DARWINIA_SCAN" | "DARWIN_SCAN" | "GPU_SCAN" => {
                if self.darwin_ftp_dir.is_empty() {
                    self.log.push_back(LogEntry::warn("Set Darwinex FTP Dir in Settings first"));
                } else if self.gpu_darwin.is_some() {
                    // GPU available — use GPU-accelerated scan
                    let _ = self.broker_tx.send(BrokerCmd::DarwinGpuScan { ftp_dir: self.darwin_ftp_dir.clone(), min_days: 90 });
                    self.log.push_back(LogEntry::info("DarwinIA scan started (GPU, 50K DARWINs)..."));
                } else {
                    // CPU fallback
                    let _ = self.broker_tx.send(BrokerCmd::DarwinFtpScan { ftp_dir: self.darwin_ftp_dir.clone(), min_days: 90 });
                    self.log.push_back(LogEntry::info("DarwinIA scan started (CPU fallback, no GPU)..."));
                }
            }
            // Drawing tools
            "DRAW_HLINE"     => self.draw_mode = DrawMode::PlacingHLine,
            "DRAW_TRENDLINE" => self.draw_mode = DrawMode::PlacingTrendP1,
            "DRAW_FIBO"      => self.draw_mode = DrawMode::PlacingFiboP1,
            "DRAW_VLINE"     => self.draw_mode = DrawMode::PlacingVLine,
            "DRAW_RECT"      => self.draw_mode = DrawMode::PlacingRectP1,
            "DRAW_RAY"       => self.draw_mode = DrawMode::PlacingRayP1,
            "DRAW_CHANNEL"   => self.draw_mode = DrawMode::PlacingChannelP1,
            "CLEAR_DRAWINGS" => { if let Some(c) = self.charts.get_mut(self.active_tab) { c.drawings.clear(); } }
            // Timeframe shortcuts
            "M1"  => { let sym = self.symbol_input.clone(); self.reload_symbol(&sym, Timeframe::M1); }
            "M5"  => { let sym = self.symbol_input.clone(); self.reload_symbol(&sym, Timeframe::M5); }
            "M15" => { let sym = self.symbol_input.clone(); self.reload_symbol(&sym, Timeframe::M15); }
            "M30" => { let sym = self.symbol_input.clone(); self.reload_symbol(&sym, Timeframe::M30); }
            "H1"  => { let sym = self.symbol_input.clone(); self.reload_symbol(&sym, Timeframe::H1); }
            "H4"  => { let sym = self.symbol_input.clone(); self.reload_symbol(&sym, Timeframe::H4); }
            "D1"  => { let sym = self.symbol_input.clone(); self.reload_symbol(&sym, Timeframe::D1); }
            "W1"  => { let sym = self.symbol_input.clone(); self.reload_symbol(&sym, Timeframe::W1); }
            "MN1" => { let sym = self.symbol_input.clone(); self.reload_symbol(&sym, Timeframe::MN1); }
            // Aliases
            "EQUITY"         => self.show_darwin_portfolio = true,
            "CALC"           => self.show_risk_calc = true,
            "TRADESTATS"     => { self.darwin_view = 0; self.show_darwin_portfolio = true; } // Portfolio Summary
            "PERF"           => { self.darwin_view = 14; self.show_darwin_portfolio = true; } // Seasonals
            "COMPARE"        => { self.darwin_view = 3; self.show_darwin_portfolio = true; } // Correlation Matrix
            "SPREAD"         => { self.darwin_view = 4; self.show_darwin_portfolio = true; } // Symbol Exposure
            "HEATMAP"        => { self.darwin_view = 14; self.show_darwin_portfolio = true; } // Seasonals
            "PROFILE"        => self.show_darwin_accounts = true,
            "SIGNAL"         => self.show_indicators_panel = true,
            "DASHBOARD"      => self.show_cache_stats = true,
            "STATUS"         => self.show_cache_stats = true,
            "IMPORT_XLSX"    => self.show_darwin_accounts = true,
            "WORKSPACE"      => { self.save_session(); self.log.push_back(LogEntry::info("Workspace saved")); }
            "BACKUP"         => { self.save_session(); self.log.push_back(LogEntry::info("Session backup saved")); }
            "QUOTE" => {
                let sym = self.symbol_input.trim().to_string();
                let _ = self.broker_tx.send(BrokerCmd::GetQuote { symbol: sym });
            }
            "CLOCK" => { let _ = self.broker_tx.send(BrokerCmd::GetMarketClock); }
            "FILLS" => { let _ = self.broker_tx.send(BrokerCmd::GetActivities { limit: 20 }); }
            "MOVERS" => { let _ = self.broker_tx.send(BrokerCmd::GetTopMovers); }
            "SEARCH" => {
                let query = self.command_input.trim().to_string();
                if query.len() >= 2 {
                    let _ = self.broker_tx.send(BrokerCmd::SearchSymbols { query });
                } else {
                    self.log.push_back(LogEntry::warn("Type at least 2 characters to search"));
                }
            }
            "HISTORY" => { let _ = self.broker_tx.send(BrokerCmd::GetOrderHistory { limit: 50 }); }
            "PIVOTS"   => self.show_pivots = !self.show_pivots,
            "SRLEVEL"  => self.show_pivots = !self.show_pivots,
            "FRACTALS"  => self.show_fractals = !self.show_fractals,
            "HARMONICS"     => self.show_harmonics = !self.show_harmonics,
            "AUTO_FIB"      => self.show_auto_fib = !self.show_auto_fib,
            "SUPPLY_DEMAND" => self.show_supply_demand = !self.show_supply_demand,
            "NNFX" => {
                // 1:1 MT5 TyphooN NNFX preset (clean reset + enable)
                // Reset all (skip sma200/kama since they get enabled below)
                self.show_sma100 = false;
                self.show_ema21 = false; self.show_bollinger = false; self.show_ichimoku = false;
                self.show_wma = false; self.show_hma = false; self.show_psar = false;
                self.show_rsi = false; self.show_macd = false; self.show_stochastic = false;
                self.show_adx = false; self.show_cci = false; self.show_williams_r = false;
                self.show_obv = false; self.show_momentum = false; self.show_volume_pane = false;
                self.show_fractals = false; self.show_harmonics = false; self.show_pivots = false;
                self.show_ehlers_ss = false; self.show_ehlers_decycler = false;
                self.show_ehlers_itl = false; self.show_ehlers_mama = false;
                self.show_ehlers_ebsw = false; self.show_ehlers_cyber = false;
                self.show_ehlers_cg = false; self.show_ehlers_roof = false;
                // Main chart: ATR_Projection + PreviousCandleLevels + MultiKAMA + MTF_MA + SupplyDemand + AutoFib
                self.show_atr_proj = true; self.show_prev_levels = true;
                self.show_kama = true; self.show_sma200 = true;
                self.show_supply_demand = true; self.show_auto_fib = true;
                // Sub-pane 1: EhlersFisherTransform | Sub-pane 2: BetterVolume
                self.show_fisher = true; self.show_better_volume = true;
                self.log.push_back(LogEntry::info("NNFX preset (1:1 MT5): ATR_Proj + PrevLevels + MultiKAMA + MTF_MA + S/D + AutoFib + Fisher + BVol"));
            }
            "RESET_IND" => {
                self.show_sma200 = false; self.show_sma100 = false; self.show_kama = false;
                self.show_ema21 = false; self.show_bollinger = false; self.show_ichimoku = false;
                self.show_wma = false; self.show_hma = false; self.show_psar = false;
                self.show_atr_proj = false; self.show_prev_levels = false;
                self.show_rsi = false; self.show_fisher = false; self.show_macd = false;
                self.show_stochastic = false; self.show_adx = false; self.show_cci = false;
                self.show_williams_r = false; self.show_obv = false; self.show_momentum = false;
                self.show_better_volume = false; self.show_volume_pane = false;
                self.log.push_back(LogEntry::info("All indicators disabled"));
            }
            "DATA_WINDOW"    => self.show_data_window = true,
            // "ALERTS" handled above (alert builder)
            "ORDER"          => { self.show_order_entry = true; self.order_symbol = self.symbol_input.clone(); }
            "PREV_LEVELS"    => self.show_prev_levels = !self.show_prev_levels,
            "CRYPTO_BACKFILL" => {
                self.show_crypto_backfill = true;
            }
            // Trading
            "OPEN_TRADE" => {
                self.show_order_entry = true;
                self.order_symbol = self.symbol_input.clone();
            }
            "CLOSE_ALL" => {
                if self.broker_connected {
                    let _ = self.broker_tx.send(BrokerCmd::CloseAll);
                    self.log.push_back(LogEntry::info("Closing all positions..."));
                } else {
                    self.log.push_back(LogEntry::warn("Connect to broker first"));
                }
            }
            "CLOSE_PARTIAL" => {
                if self.broker_connected {
                    // Close 50% of first position
                    if let Some(pos) = self.live_positions.first() {
                        let half_qty = pos.qty / 2.0;
                        let sym = pos.symbol.clone();
                        let _ = self.broker_tx.send(BrokerCmd::ClosePosition { symbol: sym.clone() });
                        self.log.push_back(LogEntry::info(format!("Closing partial {} ({:.2} qty)", sym, half_qty)));
                    } else {
                        self.log.push_back(LogEntry::warn("No positions to close"));
                    }
                } else { self.log.push_back(LogEntry::warn("Connect to broker first")); }
            }
            "SET_SL" => {
                self.draw_mode = DrawMode::PlacingHLine;
                self.log.push_back(LogEntry::info("Click chart to set SL level"));
            }
            "SET_TP" => {
                self.draw_mode = DrawMode::PlacingHLine;
                self.log.push_back(LogEntry::info("Click chart to set TP level"));
            }
            "OPEN_MG" => {
                if self.broker_connected {
                    self.log.push_back(LogEntry::info("Martingale: use Order Entry panel with opposite side"));
                    self.show_order_entry = true;
                } else { self.log.push_back(LogEntry::warn("Connect to broker first")); }
            }
            "BUY_LINES" | "SELL_LINES" => {
                self.draw_mode = DrawMode::PlacingHLine;
                self.log.push_back(LogEntry::info(format!("Click chart to place {} reference line", cmd)));
            }
            other => {
                self.log.push_back(LogEntry::warn(format!("Unknown command: {}", other)));
            }
        }
    }

    fn save_session(&self) {
        // Persist credentials to keyring + SQLite fallback on quit
        let creds = [
            (keyring::keys::ALPACA_API_KEY, self.broker_api_key.as_str()),
            (keyring::keys::ALPACA_SECRET, self.broker_secret.as_str()),
            (keyring::keys::FINNHUB_KEY, self.finnhub_key.as_str()),
            (keyring::keys::FRED_KEY, self.fred_key.as_str()),
            (keyring::keys::TT_USERNAME, self.tt_username.as_str()),
            (keyring::keys::TT_PASSWORD, self.tt_password.as_str()),
            (keyring::keys::LAN_SYNC_PASS, self.lan_sync_passphrase.as_str()),
        ];
        for (key, val) in &creds {
            let _ = keyring::store(key, val);
            if let Some(ref cache) = self.cache {
                let _ = cache.put_kv(&format!("cred:{}", key), val);
            }
        }

        let session = serde_json::json!({
            "symbol": self.symbol_input,
            "active_tab": self.active_tab,
            "tabs": self.charts.iter().map(|c| serde_json::json!({
                "symbol": c.symbol,
                "timeframe": c.timeframe.label(),
                "chart_type": c.chart_type.label(),
            })).collect::<Vec<_>>(),
            "indicators": {
                "sma200": self.show_sma200, "sma100": self.show_sma100,
                "kama": self.show_kama, "ema21": self.show_ema21,
                "bollinger": self.show_bollinger, "ichimoku": self.show_ichimoku,
                "wma": self.show_wma, "hma": self.show_hma,
                "psar": self.show_psar, "atr_proj": self.show_atr_proj,
                "prev_levels": self.show_prev_levels, "pivots": self.show_pivots,
                "fractals": self.show_fractals, "harmonics": self.show_harmonics, "supply_demand": self.show_supply_demand,
                "ehlers_ss": self.show_ehlers_ss, "ehlers_decycler": self.show_ehlers_decycler,
                "ehlers_itl": self.show_ehlers_itl, "ehlers_mama": self.show_ehlers_mama,
                "ehlers_ebsw": self.show_ehlers_ebsw, "ehlers_cyber": self.show_ehlers_cyber,
                "ehlers_cg": self.show_ehlers_cg, "ehlers_roof": self.show_ehlers_roof,
                "rsi": self.show_rsi, "fisher": self.show_fisher,
                "macd": self.show_macd, "stochastic": self.show_stochastic,
                "adx": self.show_adx, "cci": self.show_cci,
                "williams_r": self.show_williams_r, "obv": self.show_obv,
                "momentum": self.show_momentum, "better_volume": self.show_better_volume,
                "volume_pane": self.show_volume_pane,
            },
            "mtf_enabled": self.mtf_enabled,
            "mtf_cols": self.mtf_cols,
            "right_tab": match self.right_tab {
                RightTab::Trading => "trading",
                RightTab::Positions => "positions",
                RightTab::Orders => "orders",
                RightTab::Watchlist => "watchlist",
                RightTab::Risk => "risk",
            },
            "user_watchlist": self.user_watchlist,
            "lan_client_enabled": self.lan_client_enabled,
            "lan_server_ip": self.lan_server_ip,
            "lan_sync_port": self.lan_sync_port,
            "darwin_view": self.darwin_view,
            "darwin_xlsx_dir": self.darwin_xlsx_dir,
            "mt5_db_paths": self.mt5_db_paths,
            "darwin_ftp_dir": self.darwin_ftp_dir,
            // Credentials: keyring-only (secure OS storage). Session stores non-secret config.
            "broker_paper": self.broker_paper,
            "tt_sandbox": self.tt_sandbox,
            "sl_enabled": self.sl_enabled,
            "tp_enabled": self.tp_enabled,
            "windows": {
                "settings": self.show_settings,
                "darwin_accounts": self.show_darwin_accounts,
                "darwin_portfolio": self.show_darwin_portfolio,
                "risk_calc": self.show_risk_calc,
                "backtest": self.show_backtest,
                "news": self.show_news,
                "indicators_panel": self.show_indicators_panel,
                "screener": self.show_screener,
                "optimizer": self.show_optimizer,
                "sec": self.show_sec,
                "insider": self.show_insider,
                "fundamentals": self.show_fundamentals,
                "order_flow": self.show_order_flow,
                "bookmap": self.show_bookmap,
                "journal": self.show_journal,
                "var_mult": self.show_var_mult,
                "montecarlo": self.show_montecarlo,
                "earnings_calendar": self.show_earnings_calendar,
                "storage": self.show_storage,
                "lan_sync": self.show_lan_sync,
                "unusual_volume": self.show_unusual_volume,
                "sector_rotation": self.show_sector_rotation,
                "fred": self.show_fred,
                "econ_calendar": self.show_econ_calendar,
                "congress": self.show_congress,
            },
            "journal": self.journal_entries.iter().map(|e| serde_json::json!({
                "timestamp": e.timestamp, "symbol": e.symbol, "side": e.side,
                "qty": e.qty, "entry_price": e.entry_price,
                "exit_price": e.exit_price, "pnl": e.pnl,
                "strategy": e.strategy, "notes": e.notes,
            })).collect::<Vec<_>>(),
            "drawings": self.charts.get(0).map(|c| {
                c.drawings.iter().filter_map(|d| match d {
                    Drawing::HLine { price, .. } => Some(serde_json::json!({"type": "hline", "price": price})),
                    _ => None, // Only persist HLines for now (trendlines need bar indices which shift)
                }).collect::<Vec<_>>()
            }).unwrap_or_default(),
            "alerts": self.alerts.iter().map(|(p, l)| serde_json::json!({"price": p, "label": l})).collect::<Vec<_>>(),
        });
        let mut path = dirs_home();
        path.push("session.json");
        if let Ok(json) = serde_json::to_string_pretty(&session) {
            let _ = std::fs::write(&path, json);
        }
    }

    fn load_session(&mut self) {
        let mut path = dirs_home();
        path.push("session.json");
        if let Ok(data) = std::fs::read_to_string(&path) {
            if let Ok(v) = serde_json::from_str::<serde_json::Value>(&data) {
                if let Some(sym) = v["symbol"].as_str() { self.symbol_input = sym.to_string(); }
                if let Some(mtf) = v["mtf_enabled"].as_bool() { self.mtf_enabled = mtf; }
                if let Some(tab) = v["active_tab"].as_u64() { self.active_tab = tab as usize; }
                // Restore tabs: symbol, timeframe, chart type — rebuild charts from session
                if let Some(tabs) = v["tabs"].as_array() {
                    if !tabs.is_empty() {
                        // Rebuild chart set from session data
                        self.charts.clear();
                        for tab in tabs {
                            let sym = tab["symbol"].as_str().unwrap_or("CC").to_string();
                            let tf = match tab["timeframe"].as_str() {
                                Some("M1") => Timeframe::M1,
                                Some("M5") => Timeframe::M5,
                                Some("M15") => Timeframe::M15,
                                Some("M30") => Timeframe::M30,
                                Some("H1") => Timeframe::H1,
                                Some("D1") => Timeframe::D1,
                                Some("W1") => Timeframe::W1,
                                Some("MN1") => Timeframe::MN1,
                                _ => Timeframe::H4,
                            };
                            let ct = match tab["chart_type"].as_str() {
                                Some("Heikin-Ashi") => ChartType::HeikinAshi,
                                Some("Line") => ChartType::Line,
                                Some("OHLC Bars") => ChartType::OhlcBars,
                                Some("Renko") => ChartType::Renko,
                                _ => ChartType::Candle,
                            };
                            let mut chart = ChartState::new(&sym, tf);
                            chart.chart_type = ct;
                            self.charts.push(chart);
                        }
                        // Load charts: if MTF grid is active, load ALL charts; otherwise just the active tab
                        if let Some(ref cache) = self.cache {
                            if self.mtf_enabled {
                                for chart in &mut self.charts {
                                    if chart.bars.is_empty() {
                                        { let mut gpu = self.gpu_indicators.take(); chart.load(cache, &mut self.log, gpu.as_mut()); self.gpu_indicators = gpu; }
                                    }
                                }
                            } else if let Some(chart) = self.charts.get_mut(self.active_tab) {
                                { let mut gpu = self.gpu_indicators.take(); chart.load(cache, &mut self.log, gpu.as_mut()); self.gpu_indicators = gpu; }
                            }
                        }
                    }
                }
                if let Some(ind) = v.get("indicators") {
                    for (key, field) in [
                        ("sma200", &mut self.show_sma200), ("sma100", &mut self.show_sma100),
                        ("kama", &mut self.show_kama), ("ema21", &mut self.show_ema21),
                        ("bollinger", &mut self.show_bollinger), ("ichimoku", &mut self.show_ichimoku),
                        ("wma", &mut self.show_wma), ("hma", &mut self.show_hma),
                        ("psar", &mut self.show_psar), ("atr_proj", &mut self.show_atr_proj),
                        ("prev_levels", &mut self.show_prev_levels), ("pivots", &mut self.show_pivots),
                        ("fractals", &mut self.show_fractals), ("harmonics", &mut self.show_harmonics), ("supply_demand", &mut self.show_supply_demand),
                        ("ehlers_ss", &mut self.show_ehlers_ss), ("ehlers_decycler", &mut self.show_ehlers_decycler),
                        ("ehlers_itl", &mut self.show_ehlers_itl), ("ehlers_mama", &mut self.show_ehlers_mama),
                        ("ehlers_ebsw", &mut self.show_ehlers_ebsw), ("ehlers_cyber", &mut self.show_ehlers_cyber),
                        ("ehlers_cg", &mut self.show_ehlers_cg), ("ehlers_roof", &mut self.show_ehlers_roof),
                        ("rsi", &mut self.show_rsi), ("fisher", &mut self.show_fisher),
                        ("macd", &mut self.show_macd), ("stochastic", &mut self.show_stochastic),
                        ("adx", &mut self.show_adx), ("cci", &mut self.show_cci),
                        ("williams_r", &mut self.show_williams_r), ("obv", &mut self.show_obv),
                        ("momentum", &mut self.show_momentum), ("better_volume", &mut self.show_better_volume),
                        ("volume_pane", &mut self.show_volume_pane),
                    ] {
                        if let Some(b) = ind[key].as_bool() { *field = b; }
                    }
                }
                // Restore drawings
                if let Some(drawings) = v["drawings"].as_array() {
                    if let Some(chart) = self.charts.get_mut(0) {
                        for d in drawings {
                            if d["type"].as_str() == Some("hline") {
                                if let Some(price) = d["price"].as_f64() {
                                    chart.drawings.push(Drawing::HLine { price, color: HLINE_COL });
                                }
                            }
                        }
                    }
                }
                // Restore alerts
                if let Some(alerts) = v["alerts"].as_array() {
                    for a in alerts {
                        if let (Some(p), Some(l)) = (a["price"].as_f64(), a["label"].as_str()) {
                            self.alerts.push((p, l.to_string()));
                        }
                    }
                }
                // Restore MTF cols
                if let Some(cols) = v["mtf_cols"].as_u64() { self.mtf_cols = cols as usize; }
                // Restore right panel tab
                self.right_tab = match v["right_tab"].as_str() {
                    Some("positions") => RightTab::Positions,
                    Some("orders") => RightTab::Orders,
                    Some("watchlist") => RightTab::Watchlist,
                    Some("risk") => RightTab::Risk,
                    _ => RightTab::Trading,
                };
                // Restore DARWIN view
                if let Some(dv) = v["darwin_view"].as_u64() { self.darwin_view = dv as usize; }
                if let Some(dir) = v["darwin_xlsx_dir"].as_str() { self.darwin_xlsx_dir = dir.to_string(); }
                if let Some(paths) = v["mt5_db_paths"].as_array() {
                    for (i, p) in paths.iter().enumerate().take(4) {
                        if let Some(s) = p.as_str() { self.mt5_db_paths[i] = s.to_string(); }
                    }
                }
                if let Some(ftp) = v["darwin_ftp_dir"].as_str() {
                    self.darwin_ftp_dir = ftp.to_string();
                    if let Ok(mut dir) = self.shared_ftp_dir.lock() { *dir = ftp.to_string(); }
                }
                // Migration fallback: load credentials from old session.json if keyring is empty.
                // Secrets are no longer written to session.json (see save_session).
                // Once a session has been saved under the new code these keys will be absent.
                if self.finnhub_key.is_empty() {
                    if let Some(fk) = v["finnhub_key"].as_str() { self.finnhub_key = fk.to_string(); }
                }
                if self.fred_key.is_empty() {
                    if let Some(fk) = v["fred_key"].as_str() { self.fred_key = fk.to_string(); }
                }
                if self.broker_api_key.is_empty() {
                    if let Some(ak) = v["broker_api_key"].as_str() { self.broker_api_key = ak.to_string(); }
                }
                if self.broker_secret.is_empty() {
                    if let Some(bs) = v["broker_secret"].as_str() { self.broker_secret = bs.to_string(); }
                }
                if self.tt_username.is_empty() {
                    if let Some(tu) = v["tt_username"].as_str() { self.tt_username = tu.to_string(); }
                }
                if self.tt_password.is_empty() {
                    if let Some(tp) = v["tt_password"].as_str() { self.tt_password = tp.to_string(); }
                }
                if let Some(ts) = v["tt_sandbox"].as_bool() { self.tt_sandbox = ts; }
                if let Some(bp) = v["broker_paper"].as_bool() { self.broker_paper = bp; }
                // Restore user watchlist
                if let Some(wl) = v["user_watchlist"].as_array() {
                    self.user_watchlist = wl.iter().filter_map(|s| s.as_str().map(String::from)).collect();
                }
                // Restore LAN client config
                if let Some(b) = v["lan_client_enabled"].as_bool() { self.lan_client_enabled = b; }
                if let Some(s) = v["lan_server_ip"].as_str() { self.lan_server_ip = s.to_string(); }
                if let Some(s) = v["lan_sync_port"].as_str() { self.lan_sync_port = s.to_string(); }
                // Restore SL/TP state
                if let Some(sl) = v["sl_enabled"].as_bool() { self.sl_enabled = sl; }
                if let Some(tp) = v["tp_enabled"].as_bool() { self.tp_enabled = tp; }
                // Restore window visibility
                if let Some(w) = v.get("windows") {
                    if let Some(b) = w["settings"].as_bool() { self.show_settings = b; }
                    if let Some(b) = w["darwin_accounts"].as_bool() { self.show_darwin_accounts = b; }
                    if let Some(b) = w["darwin_portfolio"].as_bool() { self.show_darwin_portfolio = b; }
                    if let Some(b) = w["risk_calc"].as_bool() { self.show_risk_calc = b; }
                    if let Some(b) = w["backtest"].as_bool() { self.show_backtest = b; }
                    if let Some(b) = w["news"].as_bool() { self.show_news = b; }
                    if let Some(b) = w["indicators_panel"].as_bool() { self.show_indicators_panel = b; }
                    if let Some(b) = w["screener"].as_bool() { self.show_screener = b; }
                    if let Some(b) = w["optimizer"].as_bool() { self.show_optimizer = b; }
                    if let Some(b) = w["sec"].as_bool() { self.show_sec = b; }
                    if let Some(b) = w["insider"].as_bool() { self.show_insider = b; }
                    if let Some(b) = w["fundamentals"].as_bool() { self.show_fundamentals = b; }
                    if let Some(b) = w["order_flow"].as_bool() { self.show_order_flow = b; }
                    if let Some(b) = w["bookmap"].as_bool() { self.show_bookmap = b; }
                    if let Some(b) = w["journal"].as_bool() { self.show_journal = b; }
                    if let Some(b) = w["var_mult"].as_bool() { self.show_var_mult = b; }
                    if let Some(b) = w["montecarlo"].as_bool() { self.show_montecarlo = b; }
                    if let Some(b) = w["earnings_calendar"].as_bool() { self.show_earnings_calendar = b; }
                    if let Some(b) = w["storage"].as_bool() { self.show_storage = b; }
                    if let Some(b) = w["lan_sync"].as_bool() { self.show_lan_sync = b; }
                    if let Some(b) = w["unusual_volume"].as_bool() { self.show_unusual_volume = b; }
                    if let Some(b) = w["sector_rotation"].as_bool() { self.show_sector_rotation = b; }
                    if let Some(b) = w["fred"].as_bool() { self.show_fred = b; }
                    if let Some(b) = w["econ_calendar"].as_bool() { self.show_econ_calendar = b; }
                    if let Some(b) = w["congress"].as_bool() { self.show_congress = b; }
                }
                // Restore journal entries
                if let Some(journal) = v["journal"].as_array() {
                    for entry in journal {
                        self.journal_entries.push(JournalEntry {
                            timestamp: entry["timestamp"].as_str().unwrap_or("").to_string(),
                            symbol: entry["symbol"].as_str().unwrap_or("").to_string(),
                            side: entry["side"].as_str().unwrap_or("BUY").to_string(),
                            qty: entry["qty"].as_f64().unwrap_or(1.0),
                            entry_price: entry["entry_price"].as_f64().unwrap_or(0.0),
                            exit_price: entry["exit_price"].as_f64(),
                            pnl: entry["pnl"].as_f64(),
                            strategy: entry["strategy"].as_str().unwrap_or("").to_string(),
                            notes: entry["notes"].as_str().unwrap_or("").to_string(),
                            screenshot_path: None,
                        });
                    }
                }
                self.log.push_back(LogEntry::info("Session restored"));
            }
        }
    }

    fn export_csv(&mut self) {
        if let Some(chart) = self.charts.get(self.active_tab) {
            if chart.bars.is_empty() {
                self.log.push_back(LogEntry::warn("No bars to export"));
                return;
            }
            if let Some(path) = rfd::FileDialog::new()
                .add_filter("CSV", &["csv"])
                .set_file_name(&format!("{}_{}.csv", chart.symbol, chart.timeframe.label()))
                .set_title("Export Chart Data")
                .save_file()
            {
                match std::fs::File::create(&path) {
                    Ok(mut f) => {
                        let _ = writeln!(f, "timestamp,open,high,low,close,volume");
                        for bar in &chart.bars {
                            let _ = writeln!(f, "{},{},{},{},{},{}", bar.ts_ms, bar.open, bar.high, bar.low, bar.close, bar.volume);
                        }
                        self.log.push_back(LogEntry::info(format!("Exported {} bars to {}", chart.bars.len(), path.display())));
                    }
                    Err(e) => {
                        self.log.push_back(LogEntry::err(format!("Export failed: {}", e)));
                    }
                }
            }
        }
    }

