                                                                ui.label(egui::RichText::new(format!("{:.1}%", rb.risk_contribution_pct)).color(risk_c).small());
                                                                ui.label(egui::RichText::new(format!("{:+.2}%", rb.diversification_benefit)).color(div_c).small());
