                                ui.label(egui::RichText::new("Event").color(AXIS_TEXT).small().strong());
                                ui.label(egui::RichText::new("Impact").color(AXIS_TEXT).small().strong());
                                ui.label(egui::RichText::new("Actual").color(AXIS_TEXT).small().strong());
